'use client';

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import {
    ArrowLeft, Calendar, MapPin, Droplets, Thermometer,
    Wind, Activity, ShieldAlert, FileText, Camera, Droplet, Clock, Download, Leaf, Sprout, TrendingUp, AlertTriangle
} from 'lucide-react';
import FarmerDashboardLayout from '@/components/FarmerDashboardLayout';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

// Mock data (since no backend DB parameter logic yet)
const mockCropsData: Record<string, any> = {
    '1': { id: 1, name: 'Wheat', variety: 'HD-2967', area: '2 acres', planted: '2025-10-12', location: 'Village A, District X', soil_type: 'Alluvial Soil', irrigation_type: 'Canal Irrigation', progress: 65, stage: 'Vegetative', health_score: 92, water_req: 'Sufficient', risk: 'Low Risk' },
    '2': { id: 2, name: 'Rice', variety: 'Basmati', area: '1.5 acres', planted: '2025-11-15', location: 'Village B, District Y', soil_type: 'Black Soil', irrigation_type: 'Rainfed', progress: 80, stage: 'Flowering', health_score: 88, water_req: 'Moderate', risk: 'Medium Risk' },
    '3': { id: 3, name: 'Sugarcane', variety: 'Co-86032', area: '3 acres', planted: '2026-01-01', location: 'Village C, District Z', soil_type: 'Red Soil', irrigation_type: 'Drip Irrigation', progress: 45, stage: 'Vegetative', health_score: 65, water_req: 'Required', risk: 'High Risk' },
    '4': { id: 4, name: 'Cotton', variety: 'Bt Cotton', area: '2.5 acres', planted: '2025-12-20', location: 'Village D, District W', soil_type: 'Sandy Soil', irrigation_type: 'Sprinkler', progress: 70, stage: 'Flowering', health_score: 95, water_req: 'Sufficient', risk: 'Low Risk' }
};

const stages = ['Seed', 'Germination', 'Seedling', 'Vegetative', 'Flowering', 'Grain Formation', 'Harvest'];

export default function CropDetailsDashboard() {
    const { id } = useParams();
    const router = useRouter();
    const { t } = useTranslation();
    const [crop, setCrop] = useState<any>(null);

    useEffect(() => {
        if (id && mockCropsData[id as string]) {
            setCrop(mockCropsData[id as string]);
        } else {
            // Default generic fallback
            setCrop({
                id: id,
                name: 'Custom Crop',
                variety: 'Local',
                area: '1 acre',
                planted: new Date().toISOString().split('T')[0],
                location: 'Current GPS',
                soil_type: 'Local Soil',
                irrigation_type: 'Rainfed',
                progress: 50,
                stage: 'Vegetative',
                health_score: 85,
                water_req: 'Moderate',
                risk: 'Low Risk'
            });
        }
    }, [id]);

    if (!crop) return <FarmerDashboardLayout><div className="flex justify-center items-center h-full">Loading...</div></FarmerDashboardLayout>;

    // Calculate days since sowing
    const plantedDate = new Date(crop.planted);
    const today = new Date();
    const daysSinceSowing = Math.floor((today.getTime() - plantedDate.getTime()) / (1000 * 3600 * 24));

    const generateReport = () => {
        const doc = new jsPDF();

        doc.setFontSize(20);
        doc.text(`Crop Report: ${crop.name} (${crop.variety})`, 14, 22);

        doc.setFontSize(12);
        doc.text(`Report Generated On: ${new Date().toLocaleDateString()}`, 14, 32);

        autoTable(doc, {
            startY: 40,
            head: [['Detail', 'Information']],
            body: [
                ['Crop Name', crop.name],
                ['Variety', crop.variety],
                ['Area', crop.area],
                ['Planted Date', crop.planted],
                ['Days Since Sowing', `${daysSinceSowing} days`],
                ['Farm Location', crop.location],
                ['Soil Type', crop.soil_type],
                ['Irrigation Type', crop.irrigation_type],
                ['Current Stage', crop.stage],
                ['Health Score', `${crop.health_score} / 100`],
                ['Water Requirement', crop.water_req],
                ['Risk Level', crop.risk]
            ],
            theme: 'grid',
            headStyles: { fillColor: [16, 185, 129] } // Agri Green
        });

        doc.setFontSize(14);
        doc.text('Recent Health Timeline', 14, (doc as any).lastAutoTable.finalY + 15);

        autoTable(doc, {
            startY: (doc as any).lastAutoTable.finalY + 20,
            head: [['Date', 'Health Score', 'Disease Detected', 'Status']],
            body: [
                ['12 March', '88', 'None', 'Healthy'],
                ['18 March', '81', 'Leaf Rust', 'Needs Attention'],
                ['25 March', '90', 'Recovered', 'Healthy']
            ],
            theme: 'striped',
            headStyles: { fillColor: [59, 130, 246] }
        });

        doc.save(`${crop.name}_Report_${new Date().getTime()}.pdf`);
    };

    return (
        <FarmerDashboardLayout>
            {/* Header & Navigation */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-6 gap-4 border-b border-gray-100 pb-4">
                <div className="flex items-center gap-4">
                    <button
                        onClick={() => router.push('/crops')}
                        className="p-2 bg-white border border-gray-200 rounded-full hover:bg-gray-50 transition-colors shadow-sm"
                    >
                        <ArrowLeft size={20} className="text-gray-600" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900 tracking-tight">{crop.name} <span className="text-gray-400 font-medium text-lg">({crop.variety})</span></h1>
                        <p className="text-sm text-gray-500 font-medium capitalize mt-0.5">Crop Details Dashboard</p>
                    </div>
                </div>
                <button
                    onClick={generateReport}
                    className="flex items-center gap-2 bg-agri-green text-white px-5 py-2.5 rounded-lg text-sm font-bold shadow-sm hover:bg-green-700 transition-colors"
                >
                    <Download size={18} /> Generate Report
                </button>
            </div>

            {/* Crop Information Header Card */}
            <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="bg-white rounded-xl border border-gray-100 shadow-sm p-6 mb-6"
            >
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-4">
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1">Crop</p>
                        <p className="text-sm font-semibold text-gray-900">{crop.name}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1">Variety</p>
                        <p className="text-sm font-semibold text-gray-900">{crop.variety}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1">Area</p>
                        <p className="text-sm font-semibold text-gray-900">{crop.area}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1 flex items-center gap-1"><Calendar size={12} /> Planted</p>
                        <p className="text-sm font-semibold text-gray-900">{crop.planted}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg md:col-span-2 lg:col-span-1">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1 flex items-center gap-1"><MapPin size={12} /> Location</p>
                        <p className="text-sm font-semibold text-gray-900 truncate">{crop.location}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1">Soil Type</p>
                        <p className="text-sm font-semibold text-gray-900">{crop.soil_type}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-xs text-gray-500 font-bold uppercase mb-1">Irrigation</p>
                        <p className="text-sm font-semibold text-gray-900">{crop.irrigation_type}</p>
                    </div>
                </div>
            </motion.div>

            {/* Crop Status Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center gap-4">
                    <div className="w-12 h-12 bg-blue-50 rounded-full flex items-center justify-center text-blue-600"><Sprout size={24} /></div>
                    <div>
                        <p className="text-xs text-gray-500 font-bold uppercase mb-0.5">Current Stage</p>
                        <p className="text-lg font-bold text-gray-900">{crop.stage}</p>
                    </div>
                </div>
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center gap-4">
                    <div className="w-12 h-12 bg-cyan-50 rounded-full flex items-center justify-center text-cyan-600"><Droplets size={24} /></div>
                    <div>
                        <p className="text-xs text-gray-500 font-bold uppercase mb-0.5">Water Requirement</p>
                        <p className="text-lg font-bold text-gray-900">{crop.water_req}</p>
                    </div>
                </div>
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center ${crop.risk === 'High Risk' ? 'bg-red-50 text-red-600' : crop.risk === 'Medium Risk' ? 'bg-amber-50 text-amber-600' : 'bg-green-50 text-green-600'}`}>
                        <ShieldAlert size={24} />
                    </div>
                    <div>
                        <p className="text-xs text-gray-500 font-bold uppercase mb-0.5">Crop Risk</p>
                        <p className={`text-lg font-bold ${crop.risk === 'High Risk' ? 'text-red-700' : crop.risk === 'Medium Risk' ? 'text-amber-700' : 'text-green-700'}`}>{crop.risk}</p>
                    </div>
                </div>
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center gap-4">
                    <div className="w-12 h-12 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-600"><Activity size={24} /></div>
                    <div>
                        <p className="text-xs text-gray-500 font-bold uppercase mb-0.5">Health Score</p>
                        <div className="flex items-center gap-2">
                            <p className="text-2xl font-black text-gray-900">{crop.health_score}<span className="text-sm font-medium text-gray-500">/100</span></p>
                            {crop.health_score > 80 ? <TrendingUp size={16} className="text-green-500" /> : <TrendingUp size={16} className="text-red-500 rotate-180 transform" />}
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-6">
                <div className="lg:col-span-2 space-y-6">
                    {/* Crop Growth Cycle Animation */}
                    {/* Crop Growth Cycle Animation Visualization */}
                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm overflow-hidden">
                        <h3 className="text-lg font-bold text-gray-900 mb-6 flex items-center gap-2">
                            <Sprout className="text-agri-green" size={20} /> Animated Crop Lifecycle
                        </h3>

                        {/* 3D-styled Grow Area */}
                        <div className="relative h-64 w-full bg-gradient-to-b from-blue-50/80 to-blue-100/60 rounded-xl mb-8 overflow-hidden border border-blue-200 shadow-inner">
                            {/* Animated Sun */}
                            <motion.div
                                className="absolute top-6 w-12 h-12 bg-yellow-400 rounded-full border-2 border-yellow-300"
                                style={{ boxShadow: '0 0 40px rgba(253, 224, 71, 0.8)' }}
                                animate={{
                                    left: `${(stages.indexOf(crop.stage) / (stages.length - 1)) * 100}%`
                                }}
                                transition={{ duration: 1.5, ease: "easeOut" }}
                            />
                            {/* Clouds */}
                            <motion.div className="absolute top-10 left-1/4 w-16 h-6 bg-white/70 rounded-full blur-[1px]" animate={{ x: [0, 20, 0] }} transition={{ repeat: Infinity, duration: 8, ease: "easeInOut" }} />
                            <motion.div className="absolute top-16 left-2/3 w-24 h-8 bg-white/60 rounded-full blur-[2px]" animate={{ x: [0, -20, 0] }} transition={{ repeat: Infinity, duration: 12, ease: "easeInOut" }} />

                            {/* Plant System */}
                            <div className="absolute bottom-12 left-1/2 -translate-x-1/2 w-40 h-48 flex flex-col items-center justify-end z-10">
                                {(() => {
                                    const idx = stages.indexOf(crop.stage);
                                    const isHarvest = idx === 6;
                                    const plantColor = isHarvest ? '#d97706' : '#16a34a'; // golden vs green
                                    const stemHeight = idx >= 6 ? 160 : idx >= 5 ? 150 : idx >= 4 ? 140 : idx >= 3 ? 110 : idx >= 2 ? 70 : idx >= 1 ? 30 : 0;
                                    const showSeed = idx === 0;

                                    return (
                                        <div className="relative flex flex-col items-center justify-end w-full h-full">
                                            {showSeed && (
                                                <motion.div
                                                    initial={{ opacity: 0, scale: 0 }}
                                                    animate={{ opacity: 1, scale: 1 }}
                                                    className="absolute -bottom-6 w-5 h-3.5 bg-amber-800 rounded-[100%] border border-amber-900 shadow-sm z-0"
                                                />
                                            )}

                                            {/* Stem */}
                                            <motion.div
                                                initial={{ height: 0 }}
                                                animate={{ height: stemHeight, backgroundColor: plantColor }}
                                                transition={{ duration: 1.2, ease: "easeOut" }}
                                                className="w-3.5 shadow-md relative z-10"
                                                style={{ transformOrigin: 'bottom', borderRadius: '4px 4px 0 0' }}
                                            >
                                                {/* Leaves */}
                                                {[...Array(6)].map((_, i) => {
                                                    const side = i % 2 === 0 ? 'left' : 'right';
                                                    const bottomPos = 25 + (i * 22);
                                                    const isVisible = idx >= 2 && stemHeight > bottomPos && (
                                                        (idx === 2 && i < 2) ||
                                                        (idx === 3 && i < 4) ||
                                                        (idx >= 4)
                                                    );

                                                    return (
                                                        <motion.div
                                                            key={`leaf-${i}`}
                                                            initial={{ scale: 0, rotate: side === 'left' ? 30 : -30 }}
                                                            animate={{ scale: isVisible ? 1 : 0, backgroundColor: plantColor }}
                                                            transition={{ delay: 0.4 + (i * 0.15), duration: 0.5 }}
                                                            className="absolute shadow-sm"
                                                            style={{
                                                                width: '45px',
                                                                height: '22px',
                                                                bottom: `${bottomPos}px`,
                                                                left: side === 'left' ? '-42px' : '10px',
                                                                borderRadius: side === 'left' ? '100% 0% 100% 0%' : '0% 100% 0% 100%',
                                                                transformOrigin: side === 'left' ? 'right bottom' : 'left bottom',
                                                                border: `1px solid ${isHarvest ? '#b45309' : '#15803d'}`
                                                            }}
                                                        >
                                                            {/* Leaf Vein */}
                                                            <div className="w-full h-[1px] bg-white/30 absolute top-1/2 -translate-y-1/2" style={{ transform: side === 'left' ? 'rotate(15deg)' : 'rotate(-15deg)' }}></div>
                                                        </motion.div>
                                                    )
                                                })}

                                                {/* Flowers */}
                                                {(idx === 4) && (
                                                    <>
                                                        <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ delay: 1 }} className="absolute -top-3 -left-5 w-6 h-6 bg-yellow-300 rounded-full border-2 border-yellow-500 shadow-md">
                                                            <div className="w-2 h-2 bg-orange-400 rounded-full absolute top-1.5 left-1.5"></div>
                                                        </motion.div>
                                                        <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ delay: 1.2 }} className="absolute flex top-4 -right-6 w-5 h-5 bg-yellow-300 rounded-full border-2 border-yellow-500 shadow-md">
                                                            <div className="w-1.5 h-1.5 bg-orange-400 rounded-full absolute top-1 left-1"></div>
                                                        </motion.div>
                                                    </>
                                                )}

                                                {/* Grain/Fruit */}
                                                {(idx >= 5) && (
                                                    <>
                                                        <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ delay: 1 }} className={`absolute top-0 -left-4 w-4 h-9 ${isHarvest ? 'bg-amber-400 border-amber-600' : 'bg-green-400 border-green-600'} rounded-full border-2 shadow-md`}>
                                                            <div className="w-full h-1 bg-black/10 absolute top-2"></div>
                                                            <div className="w-full h-1 bg-black/10 absolute top-5"></div>
                                                        </motion.div>
                                                        <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ delay: 1.2 }} className={`absolute top-8 -right-4 w-4 h-9 ${isHarvest ? 'bg-amber-400 border-amber-600' : 'bg-green-400 border-green-600'} rounded-full border-2 shadow-md`}>
                                                            <div className="w-full h-1 bg-black/10 absolute top-2"></div>
                                                            <div className="w-full h-1 bg-black/10 absolute top-5"></div>
                                                        </motion.div>
                                                        <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ delay: 1.4 }} className={`absolute top-16 -left-5 w-4 h-9 ${isHarvest ? 'bg-amber-400 border-amber-600' : 'bg-green-400 border-green-600'} rounded-full border-2 shadow-md`}>
                                                            <div className="w-full h-1 bg-black/10 absolute top-2"></div>
                                                            <div className="w-full h-1 bg-black/10 absolute top-5"></div>
                                                        </motion.div>
                                                    </>
                                                )}
                                            </motion.div>
                                        </div>
                                    )
                                })()}
                            </div>

                            {/* 3D Soil Layers */}
                            <div className="absolute bottom-0 w-full h-12 bg-[#6b4226] border-t-4 border-[#54331c] z-20 shadow-[inset_0_8px_15px_rgba(0,0,0,0.25)]">
                                <div className="absolute top-1 left-10 w-16 h-2 bg-[#4a2e1b] rounded-full opacity-60"></div>
                                <div className="absolute top-4 left-1/3 w-8 h-1.5 bg-[#4a2e1b] rounded-full opacity-60"></div>
                                <div className="absolute top-2 right-1/4 w-20 h-2.5 bg-[#4a2e1b] rounded-full opacity-60"></div>
                                <div className="absolute top-6 left-2/3 w-12 h-1.5 bg-[#4a2e1b] rounded-full opacity-60"></div>
                            </div>
                        </div>

                        {/* Stage Timeline Text Progress */}
                        <div className="relative w-full overflow-x-auto pb-4 custom-scrollbar">
                            <div className="flex justify-between items-center min-w-[600px] relative px-4 pt-2">
                                {/* Connecting Line */}
                                <div className="absolute left-10 right-10 top-[15px] h-1 bg-gray-100 -z-10 rounded-full"></div>
                                <div className="absolute left-10 top-[15px] h-1 bg-agri-green -z-10 rounded-full transition-all duration-1000" style={{ width: `${(stages.indexOf(crop.stage) / (stages.length - 1)) * 90}%` }}></div>

                                {stages.map((stg, i) => {
                                    const currentIndex = stages.indexOf(crop.stage);
                                    let status = 'upcoming';
                                    if (i < currentIndex) status = 'completed';
                                    if (i === currentIndex) status = 'current';

                                    return (
                                        <div key={stg} className="flex flex-col items-center relative gap-2 shrink-0 w-24">
                                            <motion.div
                                                initial={{ scale: 0.8 }}
                                                animate={{ scale: status === 'current' ? 1.2 : 1 }}
                                                className={`w-8 h-8 rounded-full flex items-center justify-center border-[3px] ${status === 'completed' ? 'bg-agri-green border-agri-green shadow-md' :
                                                    status === 'current' ? 'bg-white border-agri-green shadow-[0_0_15px_rgba(22,163,74,0.4)] animate-pulse' :
                                                        'bg-white border-gray-200'
                                                    }`}
                                            >
                                                <div className={`w-2.5 h-2.5 rounded-full ${status === 'completed' ? 'bg-white' : status === 'current' ? 'bg-agri-green' : 'bg-gray-200'}`} />
                                            </motion.div>
                                            <span className={`text-[11px] font-bold text-center uppercase tracking-wide ${status === 'current' ? 'text-agri-green' : 'text-gray-400'}`}>
                                                {stg}
                                            </span>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>

                        {/* Smart Growth Insights */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-100 pt-6">
                            <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100/50">
                                <div className="flex items-center gap-2 text-blue-600 mb-1">
                                    <Clock size={16} />
                                    <span className="text-xs font-bold uppercase">Sowing Time</span>
                                </div>
                                <p className="text-lg font-bold text-gray-900">{daysSinceSowing} Days</p>
                                <p className="text-xs text-gray-500 mt-1">Since planting date</p>
                            </div>
                            <div className="bg-green-50/50 p-4 rounded-xl border border-green-100/50">
                                <div className="flex items-center gap-2 text-green-600 mb-1">
                                    <Sprout size={16} />
                                    <span className="text-xs font-bold uppercase">Current Phase</span>
                                </div>
                                <p className="text-lg font-bold text-gray-900">{crop.stage}</p>
                                <p className="text-xs text-gray-500 mt-1">Optimal growth rate</p>
                            </div>
                            <div className="bg-purple-50/50 p-4 rounded-xl border border-purple-100/50">
                                <div className="flex items-center gap-2 text-purple-600 mb-1">
                                    <TrendingUp size={16} />
                                    <span className="text-xs font-bold uppercase">Prediction</span>
                                </div>
                                <p className="text-sm font-bold text-gray-900 mt-1">Next: {stages[stages.indexOf(crop.stage) + 1] || 'Harvesting'}</p>
                                <p className="text-xs text-gray-500 mt-1">Expected in ~12 days</p>
                            </div>
                        </div>
                    </div>

                    {/* Crop Health Timeline */}
                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                                <Activity className="text-blue-500" size={20} /> Crop Health Timeline
                            </h3>
                            <button onClick={() => router.push('/disease')} className="text-xs font-bold text-blue-600 hover:underline">View History</button>
                        </div>

                        <div className="space-y-6 relative before:absolute before:inset-0 before:ml-5 before:-translate-x-px md:before:mx-auto md:before:translate-x-0 before:h-full before:w-0.5 before:bg-gradient-to-b before:from-transparent before:via-gray-200 before:to-transparent">
                            {[
                                { date: '25 March', score: 90, disease: 'Recovered', reco: 'Continue maintaining current irrigation level.', color: 'green', dot: 'bg-green-500' },
                                { date: '18 March', score: 81, disease: 'Leaf Rust Detected', reco: 'Apply propiconazole fungicide immediately.', color: 'red', dot: 'bg-red-500' },
                                { date: '12 March', score: 88, disease: 'None', reco: 'Crop is healthy. Applied standard NPK fertilizer.', color: 'blue', dot: 'bg-blue-500' },
                            ].map((item, idx) => (
                                <div key={idx} className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group">
                                    <div className={`flex items-center justify-center w-10 h-10 rounded-full border-4 border-white ${item.dot} shadow shrink-0 md:order-1 md:group-odd:-translate-x-1/2 md:group-even:translate-x-1/2 z-10`}>
                                        {item.color === 'green' && <Sprout size={16} className="text-white" />}
                                        {item.color === 'red' && <ShieldAlert size={16} className="text-white" />}
                                        {item.color === 'blue' && <Camera size={16} className="text-white" />}
                                    </div>
                                    <div className="w-[calc(100%-4rem)] md:w-[calc(50%-2.5rem)] bg-gray-50 p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                                        <div className="flex items-center justify-between mb-1">
                                            <p className="text-sm font-bold text-gray-900">{item.date}</p>
                                            <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${item.color === 'red' ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>Score: {item.score}</span>
                                        </div>
                                        <p className={`text-xs font-bold uppercase mb-2 ${item.color === 'red' ? 'text-red-500' : 'text-gray-500'}`}>{item.disease}</p>
                                        <p className="text-sm text-gray-600">{item.reco}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    {/* Quick Tools */}
                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                        <h3 className="text-lg font-bold text-gray-900 mb-4">Quick Actions</h3>
                        <div className="space-y-3">
                            <button
                                onClick={() => router.push('/disease')}
                                className="w-full flex items-center gap-3 bg-green-50 hover:bg-green-100 border border-green-200 p-3 rounded-lg transition-colors text-left group"
                            >
                                <div className="p-2 bg-white rounded-lg shadow-sm group-hover:bg-agri-green group-hover:text-white transition-colors">
                                    <Camera size={20} className="text-agri-green group-hover:text-white" />
                                </div>
                                <div>
                                    <p className="text-sm font-bold text-gray-900">Scan Crop Disease</p>
                                    <p className="text-xs text-gray-500">Run AI disease detection</p>
                                </div>
                            </button>
                            <button
                                onClick={() => alert("Checking water advice...")}
                                className="w-full flex items-center gap-3 bg-blue-50 hover:bg-blue-100 border border-blue-200 p-3 rounded-lg transition-colors text-left group"
                            >
                                <div className="p-2 bg-white rounded-lg shadow-sm group-hover:bg-blue-500 group-hover:text-white transition-colors">
                                    <Droplet size={20} className="text-blue-600 group-hover:text-white" />
                                </div>
                                <div>
                                    <p className="text-sm font-bold text-gray-900">Get Water Advice</p>
                                    <p className="text-xs text-gray-500">View irrigation schedules</p>
                                </div>
                            </button>
                        </div>
                    </div>

                    {/* System Alerts */}
                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                        <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                            <AlertTriangle className="text-amber-500" size={20} /> Active Alerts
                        </h3>
                        <div className="space-y-3">
                            <div className="flex items-start gap-3 bg-amber-50 rounded-lg p-3 border border-amber-100">
                                <Thermometer className="text-amber-600 mt-0.5 shrink-0" size={16} />
                                <div>
                                    <p className="text-sm font-bold text-amber-900">High Temperature Risk</p>
                                    <p className="text-xs text-amber-700 mt-1">Temperatures exceeding 35┬░C expected next week. Increase irrigation frequency to prevent heat stress.</p>
                                </div>
                            </div>
                            {crop.risk === 'High Risk' && (
                                <div className="flex items-start gap-3 bg-red-50 rounded-lg p-3 border border-red-100">
                                    <ShieldAlert className="text-red-600 mt-0.5 shrink-0" size={16} />
                                    <div>
                                        <p className="text-sm font-bold text-red-900">Disease Outbreak Vulnerability</p>
                                        <p className="text-xs text-red-700 mt-1">High humidity is creating a perfect condition for fungal infections. Apply preventative sprays.</p>
                                    </div>
                                </div>
                            )}
                            <div className="flex items-start gap-3 bg-blue-50 rounded-lg p-3 border border-blue-100">
                                <Droplets className="text-blue-600 mt-0.5 shrink-0" size={16} />
                                <div>
                                    <p className="text-sm font-bold text-blue-900">Soil Moisture Dropping</p>
                                    <p className="text-xs text-blue-700 mt-1">Sensor data indicates soil moisture is running moderately low. Plan irrigation within 48 hours.</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </FarmerDashboardLayout >
    );
}

'use client';

import { useState, useRef } from 'react';
import FarmerDashboardLayout from '@/components/FarmerDashboardLayout';
import { useTranslation } from 'react-i18next';
import { Upload, Camera, AlertTriangle, CheckCircle, FileText, Share2, Save, X, Leaf } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';

export default function ScanCropPage() {
    const { t, i18n } = useTranslation();
    const { user } = useAuth();
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [selectedImage, setSelectedImage] = useState<string | null>(null);
    const [isCameraActive, setIsCameraActive] = useState(false);
    const [analyzing, setAnalyzing] = useState(false);
    const [saving, setSaving] = useState(false);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const [result, setResult] = useState<any>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setSelectedFile(file);
            const reader = new FileReader();
            reader.onloadend = () => {
                setSelectedImage(reader.result as string);
                setResult(null);
                setIsCameraActive(false);
            };
            reader.readAsDataURL(file);
        }
    };

    const startCamera = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'environment', width: { ideal: 1024 }, height: { ideal: 1024 } }
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
            streamRef.current = stream;
            setIsCameraActive(true);
            setSelectedImage(null);
            setResult(null);
        } catch (err) {
            console.error("Camera access denied:", err);
            alert("Camera access denied. Please check permissions.");
        }
    };

    const stopCamera = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
        setIsCameraActive(false);
    };

    const capturePhoto = () => {
        if (videoRef.current) {
            const canvas = document.createElement('canvas');
            canvas.width = videoRef.current.videoWidth;
            canvas.height = videoRef.current.videoHeight;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.drawImage(videoRef.current, 0, 0);
                const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
                setSelectedImage(dataUrl);

                // Convert to file for analysis
                const byteString = atob(dataUrl.split(',')[1]);
                const mimeString = dataUrl.split(',')[0].split(':')[1].split(';')[0];
                const ab = new ArrayBuffer(byteString.length);
                const ia = new Uint8Array(ab);
                for (let i = 0; i < byteString.length; i++) {
                    ia[i] = byteString.charCodeAt(i);
                }
                const blob = new Blob([ab], { type: mimeString });
                const file = new File([blob], "camera_capture.jpg", { type: mimeString });
                setSelectedFile(file);
                stopCamera();
            }
        }
    };

    const handleAnalyze = async () => {
        if (!selectedFile) return;

        setAnalyzing(true);
        try {
            // 1. Prepare the image for the backend
            const formData = new FormData();
            formData.append('file', selectedFile);

            // 2. Send to FastAPI ML Backend
            const response = await fetch(`http://127.0.0.1:8001/predict?language=${i18n.language}`, {
                method: 'POST',
                body: formData,
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(errorData.detail || 'Failed to analyze image');
            }

            const data = await response.json();

            // 3. Map flat backend response directly to result state
            // Backend returns: disease, confidence, severity, cause, treatment, prevention, fertilizer
            setResult({
                disease: data.disease,
                diseaseLocal: data.disease.startsWith('Unknown') ? data.disease : data.disease,
                confidence: data.confidence,
                severity: (data.severity as string).toLowerCase(),
                cause: data.cause,
                treatment: data.treatment,
                prevention: data.prevention,
                fertilizer: data.fertilizer,
            });
        } catch (error: any) { // eslint-disable-line @typescript-eslint/no-explicit-any
            console.error('Scan error:', error);
            setResult({
                disease: 'Error',
                diseaseLocal: error.message === 'Failed to fetch'
                    ? 'Cannot connect to ML server. Is the Python script running?'
                    : `Analysis Error: ${error.message}`,
                confidence: 0,
                severity: 'high',
                cause: null,
                treatment: null,
                prevention: null,
                fertilizer: null,
            });
        } finally {
            setAnalyzing(false);
        }
    };

    const handleSave = async () => {
        if (!result || result.disease === 'Error') return;

        setSaving(true);
        try {
            // 1. Generate PDF Report FIRST (Prioritize User Value)
            const doc = new jsPDF();
            doc.setFontSize(22);
            doc.setTextColor(22, 163, 74);
            doc.text("Krushit Disease Diagnosis", 14, 20);

            doc.setFontSize(12);
            doc.setTextColor(100);
            doc.text(`Date: ${new Date().toLocaleDateString()}`, 14, 28);

            // Diagnosis Info
            autoTable(doc, {
                startY: 35,
                body: [
                    ['Disease Detected', result.diseaseLocal || result.disease],
                    ['Confidence', `${result.confidence}%`],
                    ['Severity', String(result.severity).toUpperCase()],
                ],
                theme: 'striped',
                headStyles: { fillColor: [22, 163, 74] }
            });

            // Treatment & Prevention
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const finalY = (doc as any).lastAutoTable.finalY + 10;

            if (result.treatment || result.prevention) {
                doc.setFontSize(14);
                doc.setTextColor(0);
                doc.text("Treatment Plan", 14, finalY);

                autoTable(doc, {
                    startY: finalY + 5,
                    head: [['Category', 'Details']],
                    body: [
                        ['Cause', result.cause || 'N/A'],
                        ['Treatment', result.treatment || 'N/A'],
                        ['Prevention', result.prevention || 'N/A'],
                        ['Fertilizer', result.fertilizer || 'N/A'],
                    ],
                    styles: { cellWidth: 'wrap' },
                    columnStyles: { 0: { cellWidth: 40 } }
                });
            }

            // Save PDF
            const fileName = result.disease.startsWith('Unknown')
                ? `Scan_Report_Index_${result.disease.split('_').pop()}.pdf`
                : `Disease_Report_${result.disease.replace(/\s+/g, '_')}.pdf`;
            doc.save(fileName);

            // 2. Try Save to Supabase (Best Effort)
            if (user) {
                try {
                    const { error } = await supabase.from('disease_scans').insert({
                        user_id: user.id,
                        disease_detected: result.disease,
                        confidence: result.confidence,
                        severity: result.severity,
                        image_url: selectedImage || '',
                        treatment: result.treatment || '',
                        prevention: result.prevention || ''
                    });

                    if (error) throw error;
                    alert('Γ£à Report saved to cloud & downloaded!');
                } catch (dbError: any) { // eslint-disable-line @typescript-eslint/no-explicit-any
                    console.warn('Cloud save failed (RLS likely):', dbError);
                    alert('ΓÜá∩╕Å Report downloaded. (Cloud save failed due to permissions)');
                }
            } else {
                alert('Γ£à Report downloaded! (Log in to save to cloud history)');
            }

        } catch (error: any) { // eslint-disable-line @typescript-eslint/no-explicit-any
            console.error('PDF Generation error:', error);
            alert('Γ¥î Failed to generate report: ' + error.message);
        } finally {
            setSaving(false);
        }
    };

    const handleShare = async () => {
        if (!result) return;

        const shareData = {
            title: 'Krushit Disease Scan',
            text: `I scanned my crop using Krushit! Detected: ${result.diseaseLocal} (${result.confidence}% confidence).`,
            url: window.location.href
        };

        try {
            if (navigator.share) {
                await navigator.share(shareData);
            } else {
                await navigator.clipboard.writeText(`${shareData.title}\n${shareData.text}`);
                alert('Analysis copied to clipboard!');
            }
        } catch (err) {
            console.error('Share failed:', err);
        }
    };

    return (
        <FarmerDashboardLayout>
            <div className="max-w-5xl mx-auto">
                <div className="mb-8">
                    <h1 className="text-2xl font-bold text-gray-900 tracking-tight">{t('nav.scanCrop')}</h1>
                    <p className="text-sm text-gray-500">{t('scan.subtitle')}</p>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {/* Left Column: Input */}
                    <div className="space-y-6">
                        <div className="bg-white rounded-2xl border border-gray-200 shadow-sm p-6">
                            <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                                <Camera size={20} className="text-agri-green" /> {t('scan.uploadTitle')}
                            </h2>

                            {/* Drop Zone */}
                            <div
                                className={`border-2 border-dashed rounded-xl h-80 flex flex-col items-center justify-center transition-all duration-200 relative overflow-hidden group ${selectedImage || isCameraActive ? 'border-agri-green/50 bg-gray-50' : 'border-gray-300'
                                    }`}
                            >
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    accept="image/*"
                                    onChange={handleImageUpload}
                                    className="hidden"
                                />

                                {isCameraActive ? (
                                    <div className="w-full h-full relative">
                                        <video
                                            ref={videoRef}
                                            autoPlay
                                            playsInline
                                            className="w-full h-full object-cover"
                                        />
                                        <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-4">
                                            <button
                                                onClick={capturePhoto}
                                                className="bg-agri-green text-white p-4 rounded-full shadow-lg hover:scale-110 active:scale-95 transition-transform"
                                            >
                                                <Camera size={24} />
                                            </button>
                                            <button
                                                onClick={stopCamera}
                                                className="bg-red-500 text-white p-4 rounded-full shadow-lg hover:scale-110 active:scale-95 transition-transform"
                                            >
                                                <X size={24} />
                                            </button>
                                        </div>
                                    </div>
                                ) : selectedImage ? (
                                    <>
                                        {/* eslint-disable-next-line @next/next/no-img-element */}
                                        <img src={selectedImage} alt="Crop" className="w-full h-full object-contain p-2" />
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setSelectedImage(null);
                                                setResult(null);
                                            }}
                                            className="absolute top-4 right-4 bg-white/90 text-gray-600 hover:text-red-500 p-2 rounded-full shadow-sm transition-colors border border-gray-200"
                                        >
                                            <X size={18} />
                                        </button>
                                    </>
                                ) : (
                                    <div
                                        onClick={() => fileInputRef.current?.click()}
                                        className="text-center p-6 cursor-pointer w-full h-full flex flex-col items-center justify-center hover:bg-green-50/50 transition-colors"
                                    >
                                        <div className="w-16 h-16 bg-green-100/50 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                            <Upload size={32} className="text-agri-green/80" />
                                        </div>
                                        <p className="text-sm font-semibold text-gray-700 mb-1">{t('scan.clickUpload')}</p>
                                        <p className="text-xs text-gray-400">{t('scan.supports')}</p>
                                    </div>
                                )}
                            </div>

                            <div className="mt-6 space-y-3">
                                {!isCameraActive && (
                                    <div className="flex gap-3">
                                        <button
                                            onClick={() => fileInputRef.current?.click()}
                                            className="flex-1 py-3 px-4 rounded-xl border border-gray-200 text-gray-700 font-semibold hover:bg-gray-50 transition-colors flex items-center justify-center gap-2 text-sm"
                                        >
                                            <Upload size={18} /> {t('scan.selectFile')}
                                        </button>
                                        <button
                                            onClick={startCamera}
                                            className="flex-1 py-3 px-4 rounded-xl border border-agri-green text-agri-green font-semibold hover:bg-green-50 transition-colors flex items-center justify-center gap-2 text-sm"
                                        >
                                            <Camera size={18} /> {t('scan.takePhoto')}
                                        </button>
                                    </div>
                                )}

                                <button
                                    onClick={handleAnalyze}
                                    disabled={!selectedImage || analyzing}
                                    className={`w-full py-4 px-4 rounded-xl text-white font-bold transition-all flex items-center justify-center gap-2 text-base shadow-lg ${!selectedImage || analyzing
                                        ? 'bg-gray-300 cursor-not-allowed shadow-none'
                                        : 'bg-gradient-to-r from-agri-green to-emerald-600 hover:shadow-agri-green/30 hover:-translate-y-0.5'
                                        }`}
                                >
                                    {analyzing ? (
                                        <span className="flex items-center gap-2">
                                            <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                                            {t('scan.analyzing')}
                                        </span>
                                    ) : (
                                        <>
                                            <Leaf size={20} />
                                            {t('scan.analyze')}
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>

                        {/* Tips */}
                        <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 flex gap-3">
                            <div className="shrink-0 mt-0.5">
                                <div className="w-5 h-5 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center text-xs font-bold">i</div>
                            </div>
                            <div>
                                <h4 className="text-sm font-bold text-blue-900 mb-1">{t('scan.tipTitle')}</h4>
                                <p className="text-xs text-blue-700 leading-relaxed">{t('scan.tipDesc')}</p>
                            </div>
                        </div>
                    </div>

                    {/* Right Column: Results */}
                    <div className="space-y-6">
                        <AnimatePresence mode="wait">
                            {result ? (
                                <motion.div
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, y: -10 }}
                                    className="space-y-4"
                                >
                                    {/* Diagnosis Card */}
                                    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm p-6 relative overflow-hidden">
                                        <div className={`absolute top-0 left-0 w-2 h-full ${result.severity === 'high' ? 'bg-red-500' : result.severity === 'medium' ? 'bg-amber-500' : 'bg-green-500'
                                            }`}></div>

                                        <div className="pl-4">
                                            <div className="flex justify-between items-start mb-4">
                                                <div>
                                                    <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">{t('scan.detected')}</p>
                                                    <h3 className="text-2xl font-bold text-gray-900">{result.diseaseLocal}</h3>
                                                </div>
                                                <div className="text-right">
                                                    <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">{t('scan.confidence')}</p>
                                                    <p className="text-2xl font-bold text-agri-green">{result.confidence}%</p>
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-3 mb-6">
                                                <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase flex items-center gap-1.5 ${result.severity === 'high' ? 'bg-red-100 text-red-700' :
                                                    result.severity === 'medium' ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'
                                                    }`}>
                                                    <AlertTriangle size={12} /> {result.severity} {t('scan.severity')}
                                                </span>
                                            </div>

                                            {/* Cause */}
                                            {result.cause && (
                                                <div className="bg-blue-50 rounded-xl p-4 border border-blue-100 mb-4">
                                                    <h4 className="text-sm font-bold text-blue-900 mb-2 flex items-center gap-2">
                                                        <AlertTriangle size={16} />
                                                        Cause
                                                    </h4>
                                                    <p className="text-sm text-blue-800 leading-relaxed">
                                                        {result.cause}
                                                    </p>
                                                </div>
                                            )}

                                            {/* Treatment Solution */}
                                            {result.treatment && (
                                                <div className="bg-green-50 rounded-xl p-4 border border-green-100 mb-4">
                                                    <h4 className="text-sm font-bold text-green-900 mb-3 flex items-center gap-2">
                                                        <CheckCircle size={16} />
                                                        Treatment Solution
                                                    </h4>
                                                    <p className="text-sm text-green-800 leading-relaxed">{result.treatment}</p>
                                                </div>
                                            )}

                                            {/* Prevention */}
                                            {result.prevention && (
                                                <div className="bg-purple-50 rounded-xl p-4 border border-purple-100 mb-4">
                                                    <h4 className="text-sm font-bold text-purple-900 mb-3 flex items-center gap-2">
                                                        <AlertTriangle size={16} />
                                                        Prevention Tips
                                                    </h4>
                                                    <p className="text-sm text-purple-800 leading-relaxed">{result.prevention}</p>
                                                </div>
                                            )}

                                            {/* Fertilizer Recommendation */}
                                            {result.fertilizer && (
                                                <div className="bg-amber-50 rounded-xl p-4 border border-amber-100 mb-4">
                                                    <h4 className="text-sm font-bold text-amber-900 mb-2 flex items-center gap-2">
                                                        <Leaf size={16} />
                                                        Fertilizer Recommendation
                                                    </h4>
                                                    <p className="text-sm text-amber-800 leading-relaxed">
                                                        {result.fertilizer}
                                                    </p>
                                                </div>
                                            )}

                                        </div>
                                    </div>

                                    {/* Action Buttons */}
                                    <div className="grid grid-cols-2 gap-4">
                                        <button
                                            onClick={handleSave}
                                            disabled={saving}
                                            className="flex items-center justify-center gap-2 py-3 bg-white border border-gray-200 text-gray-700 font-semibold rounded-xl hover:bg-gray-50 disabled:opacity-50 transition-colors shadow-sm text-sm"
                                        >
                                            {saving ? (
                                                <span className="w-4 h-4 border-2 border-agri-green/30 border-t-agri-green rounded-full animate-spin"></span>
                                            ) : (
                                                <Save size={18} />
                                            )}
                                            {saving ? t('auth.processing') : t('scan.save')}
                                        </button>
                                        <button
                                            onClick={handleShare}
                                            className="flex items-center justify-center gap-2 py-3 bg-white border border-gray-200 text-gray-700 font-semibold rounded-xl hover:bg-gray-50 transition-colors shadow-sm text-sm"
                                        >
                                            <Share2 size={18} /> {t('scan.share')}
                                        </button>
                                    </div>
                                </motion.div>
                            ) : (
                                <motion.div
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    className="bg-gray-50 border-2 border-dashed border-gray-200 rounded-2xl h-full min-h-[300px] flex flex-col items-center justify-center text-center p-8"
                                >
                                    <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                                        <CheckCircle size={32} className="text-gray-300" />
                                    </div>
                                    <h3 className="text-lg font-bold text-gray-900 mb-1">{t('scan.pendingTitle')}</h3>
                                    <p className="text-sm text-gray-500 max-w-xs mx-auto">{t('scan.pendingDesc')}</p>
